import{_ as r,M as d,p as i,q as l,R as e,t as s,N as t,a1 as n}from"./framework-e0dd9823.js";const o={},h=e("h1",{id:"每周一词-address",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#每周一词-address","aria-hidden":"true"},"#"),s(" 每周一词-Address")],-1),c=e("p",null,"2023 年 5 月 2 日 17:55:44",-1),u={href:"https://www.bbc.co.uk/learningenglish/chinese/features/english-in-a-minute/ep-230317",target:"_blank",rel:"noopener noreferrer"},_=n('<h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><p>名词 “address” 的意思是 “地址，住址”。除此之外，“address” 还可以作动词用，意思包括 “（在信封或包裹上）写上地址”、在正式场合中 “（向他人）讲话，致词” 、“称呼（某人）”。看视频，学习 “address” 的这些用法。</p><h2 id="用法总结" tabindex="-1"><a class="header-anchor" href="#用法总结" aria-hidden="true">#</a> 用法总结</h2><ol><li>名词 “address” 的意思是 “地址”。</li></ol><ul><li>What&#39;s the address for the party?</li><li>I&#39;ve just sent you the address.</li></ul><ol start="2"><li>动词 “address” 的意思是 “（在信封或包裹上）写上姓名或地址”。</li></ol><ul><li>Why did you open this letter? It was addressed to me.</li><li>We can&#39;t find where your parcel is because it was wrongly addressed.</li></ul><ol start="3"><li>名词 “address” 搭配 “website” 或 “email”，组成 “website address（网址）”、“email address（邮箱地址）”。</li></ol><ul><li>Our website address is bbclearningenglish.com/chinese.</li><li>What&#39;s your email address?</li></ul><ol start="4"><li>在正式场合中，动词 “address” 可以用来指 “对（一个人或一群人）讲话，致词”；“称呼（某人）”。</li></ol><ul><li>The businesswoman addressed everyone in the meeting.</li><li>Remember, he likes to be addressed as &#39;Sir&#39;.</li></ul>',11);function m(p,b){const a=d("ExternalLinkIcon");return i(),l("div",null,[h,c,e("p",null,[e("a",u,[s("BBC"),t(a)])]),_])}const w=r(o,[["render",m],["__file","word-address.html.vue"]]);export{w as default};
